// --- Input Validation ---

function sanitizeUsername(input) {
  if (typeof input !== 'string') return null;
  const trimmed = input.trim();
  // Allowlist: alphanumeric, underscores, hyphens, dots, 3-64 chars
  const usernameRegex = /^[a-zA-Z0-9._-]{3,64}$/;
  if (!usernameRegex.test(trimmed)) return null;
  return trimmed.toLowerCase();
}

function validatePassword(input) {
  if (typeof input !== 'string') return false;
  // Minimum 8 chars, maximum 128 chars to prevent DoS via extremely long passwords
  if (input.length < 8 || input.length > 128) return false;
  return true;
}

// --- Rate Limiting (per-IP, stored in KV with TTL) ---

async function checkRateLimit(env, identifier, maxAttempts = 5, windowSeconds = 300) {
  const key = `ratelimit:${identifier}`;
  const record = await env.SESSIONS.get(key, { type: 'json' });

  if (!record) {
    await env.SESSIONS.put(key, JSON.stringify({ attempts: 1, firstAttempt: Date.now() }), {
      expirationTtl: windowSeconds,
    });
    return { allowed: true, remaining: maxAttempts - 1 };
  }

  if (record.attempts >= maxAttempts) {
    return { allowed: false, remaining: 0 };
  }

  record.attempts += 1;
  const elapsed = (Date.now() - record.firstAttempt) / 1000;
  const remainingTtl = Math.max(Math.ceil(windowSeconds - elapsed), 60);

  await env.SESSIONS.put(key, JSON.stringify(record), {
    expirationTtl: remainingTtl,
  });

  return { allowed: true, remaining: maxAttempts - record.attempts };
}

// --- Failed Login Tracking (per-username) ---

async function checkAccountLockout(env, username, maxFailures = 10, lockoutSeconds = 900) {
  const key = `lockout:${username}`;
  const record = await env.SESSIONS.get(key, { type: 'json' });

  if (!record) return { locked: false };

  if (record.failures >= maxFailures) {
    return { locked: true };
  }

  return { locked: false };
}

async function recordFailedLogin(env, username, maxFailures = 10, lockoutSeconds = 900) {
  const key = `lockout:${username}`;
  const record = await env.SESSIONS.get(key, { type: 'json' });

  const newRecord = record
    ? { failures: record.failures + 1, firstFailure: record.firstFailure }
    : { failures: 1, firstFailure: Date.now() };

  await env.SESSIONS.put(key, JSON.stringify(newRecord), {
    expirationTtl: lockoutSeconds,
  });
}

async function clearFailedLogins(env, username) {
  const key = `lockout:${username}`;
  await env.SESSIONS.delete(key);
}

// --- Cryptographic Utilities ---

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    'raw',
    encoder.encode(password),
    'PBKDF2',
    false,
    ['deriveBits']
  );

  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'PBKDF2',
      salt: hexToArrayBuffer(salt),
      iterations: 100000,
      hash: 'SHA-256',
    },
    keyMaterial,
    256
  );

  return arrayBufferToHex(derivedBits);
}

function generateSalt() {
  const saltBuffer = new Uint8Array(32);
  crypto.getRandomValues(saltBuffer);
  return arrayBufferToHex(saltBuffer.buffer);
}

function generateSessionToken() {
  const tokenBuffer = new Uint8Array(32);
  crypto.getRandomValues(tokenBuffer);
  return arrayBufferToHex(tokenBuffer.buffer);
}

function arrayBufferToHex(buffer) {
  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
}

function hexToArrayBuffer(hex) {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
  }
  return bytes.buffer;
}

// --- Constant-time comparison to prevent timing attacks ---

function constantTimeEqual(a, b) {
  if (a.length !== b.length) {
    // Still do a comparison to avoid timing leak on length check
    // Compare against itself to burn the same time
    const dummy = a;
    let result = 1;
    for (let i = 0; i < dummy.length; i++) {
      result |= dummy.charCodeAt(i) ^ dummy.charCodeAt(i);
    }
    return false;
  }

  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

// --- Request Handlers ---

async function handleLogin(request, env, corsHeaders) {
  // Extract client IP for rate limiting
  const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';

  // Check IP-based rate limit
  const rateCheck = await checkRateLimit(env, clientIP);
  if (!rateCheck.allowed) {
    return new Response(
      JSON.stringify({ error: 'Too many requests. Please try again later.' }),
      {
        status: 429,
        headers: {
          ...corsHeaders,
          'Retry-After': '300',
        },
      }
    );
  }

  // Parse and validate request body
  let body;
  try {
    const contentType = request.headers.get('Content-Type') || '';
    if (!contentType.includes('application/json')) {
      return new Response(
        JSON.stringify({ error: 'Content-Type must be application/json' }),
        { status: 400, headers: corsHeaders }
      );
    }

    const rawBody = await request.text();
    // Limit body size to prevent abuse
    if (rawBody.length > 1024) {
      return new Response(JSON.stringify({ error: 'Request body too large' }), {
        status: 413,
        headers: corsHeaders,
      });
    }
    body = JSON.parse(rawBody);
  } catch {
    return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
      status: 400,
      headers: corsHeaders,
    });
  }

  // Validate and sanitize username
  const username = sanitizeUsername(body.username);
  if (!username) {
    return new Response(
      JSON.stringify({ error: 'Invalid username format. Use 3-64 alphanumeric characters, dots, hyphens, or underscores.' }),
      { status: 400, headers: corsHeaders }
    );
  }

  // Validate password
  if (!validatePassword(body.password)) {
    return new Response(
      JSON.stringify({ error: 'Invalid password format. Must be 8-128 characters.' }),
      { status: 400, headers: corsHeaders }
    );
  }

  // Check account lockout
  const lockoutCheck = await checkAccountLockout(env, username);
  if (lockoutCheck.locked) {
    return new Response(
      JSON.stringify({ error: 'Account temporarily locked due to too many failed attempts. Please try again later.' }),
      { status: 423, headers: corsHeaders }
    );
  }

  // Retrieve user record from KV
  const userRecordRaw = await env.USER_DB.get(`user:${username}`, { type: 'json' });

  if (!userRecordRaw) {
    // Perform a dummy hash to prevent timing-based user enumeration
    const dummySalt = generateSalt();
    await hashPassword(body.password, dummySalt);

    // Record failed attempt (use generic key to avoid revealing user existence)
    await recordFailedLogin(env, username);

    // Use generic error message to prevent user enumeration
    return new Response(
      JSON.stringify({ error: 'Invalid username or password' }),
      { status: 401, headers: corsHeaders }
    );
  }

  // Verify password
  const computedHash = await hashPassword(body.password, userRecordRaw.salt);

  if (!constantTimeEqual(computedHash, userRecordRaw.passwordHash)) {
    await recordFailedLogin(env, username);

    return new Response(
      JSON.stringify({ error: 'Invalid username or password' }),
      { status: 401, headers: corsHeaders }
    );
  }

  // Check if account is disabled
  if (userRecordRaw.disabled) {
    return new Response(
      JSON.stringify({ error: 'Account is disabled. Contact support.' }),
      { status: 403, headers: corsHeaders }
    );
  }

  // Clear failed login attempts on successful login
  await clearFailedLogins(env, username);

  // Generate session token
  const sessionToken = generateSessionToken();
  const sessionExpiry = 3600; // 1 hour TTL

  // Store session in KV with expiration
  const sessionData = {
    username: username,
    createdAt: Date.now(),
    clientIP: clientIP,
    userAgent: request.headers.get('User-Agent') || 'unknown',
  };

  await env.SESSIONS.put(`session:${sessionToken}`, JSON.stringify(sessionData), {
    expirationTtl: sessionExpiry,
  });

  // Log successful authentication (without sensitive data)
  console.log(
    JSON.stringify({
      event: 'login_success',
      username: username,
      timestamp: new Date().toISOString(),
      // Do NOT log session tokens, passwords, or full IPs in production
    })
  );

  return new Response(
    JSON.stringify({
      success: true,
      sessionToken: sessionToken,
      expiresIn: sessionExpiry,
    }),
    {
      status: 200,
      headers: corsHeaders,
    }
  );
}

async function handleLogout(request, env, corsHeaders) {
  // Extract session token from Authorization header
  const authHeader = request.headers.get('Authorization') || '';
  const tokenMatch = authHeader.match(/^Bearer ([a-f0-9]{64})$/);

  if (!tokenMatch) {
    return new Response(
      JSON.stringify({ error: 'Invalid or missing authorization token' }),
      { status: 401, headers: corsHeaders }
    );
  }

  const sessionToken = tokenMatch[1];

  // Verify session exists before deleting
  const sessionData = await env.SESSIONS.get(`session:${sessionToken}`);
  if (!sessionData) {
    return new Response(
      JSON.stringify({ error: 'Session not found or already expired' }),
      { status: 401, headers: corsHeaders }
    );
  }

  // Delete the session
  await env.SESSIONS.delete(`session:${sessionToken}`);

  console.log(
    JSON.stringify({
      event: 'logout',
      timestamp: new Date().toISOString(),
    })
  );

  return new Response(
    JSON.stringify({ success: true, message: 'Logged out successfully' }),
    { status: 200, headers: corsHeaders }
  );
}

async function handleVerify(request, env, corsHeaders) {
  // Extract session token from Authorization header
  const authHeader = request.headers.get('Authorization') || '';
  const tokenMatch = authHeader.match(/^Bearer ([a-f0-9]{64})$/);

  if (!tokenMatch) {
    return new Response(
      JSON.stringify({ error: 'Invalid or missing authorization token' }),
      { status: 401, headers: corsHeaders }
    );
  }

  const sessionToken = tokenMatch[1];

  // Look up session
  const sessionDataRaw = await env.SESSIONS.get(`session:${sessionToken}`, { type: 'json' });

  if (!sessionDataRaw) {
    return new Response(
      JSON.stringify({ error: 'Session expired or invalid' }),
      { status: 401, headers: corsHeaders }
    );
  }

  // Return session info (excluding sensitive fields)
  return new Response(
    JSON.stringify({
      valid: true,
      username: sessionDataRaw.username,
      createdAt: sessionDataRaw.createdAt,
    }),
    { status: 200, headers: corsHeaders }
  );
}

